n_qubits = 180

# Convert strings to PauliStrings
pauli_strs = [stim.PauliString(s) for s in stabilizers]

# Check for anticommutation
print(f"Total stabilizers: {len(pauli_strs)}")

# Find independent set using greedy approach
def find_independent_stabilizers(stabs):
    """Keep only commuting stabilizers"""
    result = []
    for i, s in enumerate(stabs):
        commutes = True
        for r in result:
            # Two Pauli strings anticommute if their product has -1 sign when neither original has a sign
            if not s.commutes(r):
                commutes = False
                break
        if commutes:
            result.append(s)
    return result

independent_stabs = find_independent_stabilizers(pauli_strs)
print(f"Independent commuting stabilizers: {len(independent_stabs)}")

# Use stim to synthesize the circuit from stabilizers
tableau = stim.Tableau.from_stabilizers(independent_stabs, allow_redundant=True, allow_underconstrained=True)
circuit = tableau.to_circuit(method='graph_state')

print("Generated circuit:")
print(circuit)

# Check gate counts
cx_count = 0
vol = 0
for inst in circuit:
    name = inst.name
    if name in ['CX', 'CY', 'CZ', 'CNOT']:
        cx_count += len(inst.targets_copy()) // 2
    if name not in ['TICK', 'QUBIT_COORDS']:
        vol += len(inst.targets_copy())

print(f"\nCX count: {cx_count}")
print(f"Volume: {vol}")
